/**
 * @param {number[]} costs
 * @param {number} coins
 * @return {number}
 */
var maxIceCream = function(costs, coins) {
    const n = costs.length;
    let min = Infinity;
    let max = -Infinity;
    let total = 0;

    for (const cost of costs) {
        if (cost < min) min = cost;
        if (cost > max) max = cost;
        total += cost;
    }

    if (coins >= total) {
        return n;
    }

    const arr = new Array(max - min + 1).fill(0);

    for (const cost of costs) {
        arr[cost - min]++;
    }

    let res = 0;

    for (let cost = min; cost <= max; cost++) {
        if (cost > coins) break;

        const pos = cost - min;
        if (arr[pos] === 0) continue;

        const usableCoins = Math.min(Math.floor(coins / cost), arr[pos]);
        coins -= usableCoins * cost;
        res += usableCoins;
    }

    return res;
};

